const transcript = ($json.transcript || "").toLowerCase();

// get filename from previous node
const fileName = ($node["Read/Write Files from Disk"].json.fileName || "").toLowerCase();

// detect call type
const call_type = fileName.includes("onboarding") ? "onboarding" : "demo";

// extract account id
const account_id = fileName.split("_")[0] || "unknown";

return {
  transcript,
  call_type,
  account_id,
  file_name: fileName
};

const transcript = $json.text || $json.transcript || "";

const account_id = $json.account_id;
const file_name = $json.file_name;

return [{
  account_id,
  file_name,
  transcript,
  company_name: "",
  business_hours: "",
  services_supported: [],
  emergency_definition: [],
  notes: transcript.substring(0,200)
}];

const data = Buffer.from(JSON.stringify($json.agent_spec, null, 2));

return [
{
  binary: {
    data: {
      data,
      mimeType: "application/json",
      fileName: "agent_spec.json"
    }
  },
  json: $json
}
];

const memoText = $json.data;

const memo_v1 = JSON.parse(memoText);

return [
{
  json: {
    ...$json,
    memo_v1
  }
}
];

const transcript = ($json.transcript || "").toLowerCase();

let updates = {
  business_hours: "",
  services_supported: [],
  emergency_definition: []
};

// Example rule extraction
if (transcript.includes("24/7") || transcript.includes("24 hours")) {
  updates.business_hours = "24/7";
}

if (transcript.includes("inspection")) {
  updates.services_supported.push("inspection");
}

if (transcript.includes("fire alarm")) {
  updates.emergency_definition.push("fire alarm trigger");
}

if (transcript.includes("sprinkler")) {
  updates.emergency_definition.push("sprinkler leak");
}

return [
{
  ...$json,
  updates
}
];

const memo_v1 = $json.memo_v1;
const updates = $json.updates;

const memo_v2 = {
  ...memo_v1,
  ...updates,
  version: "v2",
  updated_at: new Date().toISOString()
};

return [
{
  ...$json,
  memo_v2
}
];

const agent_spec_v2 = {
  agent_name: `Clara - ${$json.account_id}`,
  version: "v2",
  voice_style: "professional",

  system_prompt: `
You are Clara, an AI phone assistant.

Business hours: ${$json.memo_v2.business_hours}

Emergency definitions:
${$json.memo_v2.emergency_definition.join(", ")}

Services supported:
${$json.memo_v2.services_supported.join(", ")}

During business hours:
- greet caller
- ask reason for call
- collect name and phone number
- transfer if needed

After hours:
- determine if emergency
- collect caller details
- attempt transfer or schedule follow-up
`
};

return [
{
  ...$json,
  agent_spec_v2
}
];

const data = Buffer.from(JSON.stringify($json.agent_spec_v2, null, 2));

return [{
  binary: {
    data: {
      data,
      mimeType: "application/json",
      fileName: "agent_spec.json"
    }
  },
  json: $json
}];

const data = Buffer.from(JSON.stringify($json.memo_v2, null, 2));

return [{
  binary: {
    data: {
      data,
      mimeType: "application/json",
      fileName: "memo.json"
    }
  },
  json: $json
}];

const memo_v1 = $json.memo_v1 || {};
const memo_v2 = $json.memo_v2 || {};

let changes = [];

if (memo_v1.business_hours !== memo_v2.business_hours) {
  changes.push("Business hours updated");
}

if (JSON.stringify(memo_v1.services_supported) !== JSON.stringify(memo_v2.services_supported)) {
  changes.push("Services supported updated");
}

if (JSON.stringify(memo_v1.emergency_definition) !== JSON.stringify(memo_v2.emergency_definition)) {
  changes.push("Emergency definitions updated");
}

const changelog = {
  account_id: $json.account_id,
  version_from: "v1",
  version_to: "v2",
  changes,
  updated_at: new Date().toISOString()
};

return [{
  ...$json,
  changelog
}];

const data = Buffer.from(JSON.stringify($json.changelog, null, 2));

return [{
  json: $json,
  binary: {
    data: {
      data,
      mimeType: "application/json",
      fileName: `changelog.json`
    }
  }
}];

const data = Buffer.from(JSON.stringify($json.memo, null, 2));

return [{
  binary: {
    data: {
      data,
      mimeType: "application/json",
      fileName: "memo.json"
    }
  },
  json: $json
}];
